# Example using a simple responsive navigation toggle in JavaScript
# This snippet assumes a basic HTML/CSS structure with a mobile menu button
document.addEventListener('DOMContentLoaded', () => {
  const menuButton = document.getElementById('menu-button');
  const navMenu = document.getElementById('nav-menu');

  menuButton.addEventListener('click', () => {
    navMenu.classList.toggle('active');
    // Ensure the menu closes when clicking outside on mobile
    document.addEventListener('click', (e) => {
      if (!navMenu.contains(e.target) && !menuButton.contains(e.target)) {
        navMenu.classList.remove('active');
      }
    }, { once: true });
  });
});

This handles the edge case where the mobile navigation might not align properly on smaller screens by ensuring it toggles correctly and closes when tapping outside.
